#include <bits/stdc++.h>
using namespace std;

class Calculator {
public:
    int add(int a, int b) const { return a + b; }
    int subtract(int a, int b) const { return a - b; }
    long long multiply(int a, int b) const { return 1LL * a * b; }
    string divide(int a, int b) const {
        if (b == 0) return "Division by zero";
        return to_string(a / b);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    Calculator calc;
    for (int i = 0; i < n; ++i) {
        string op; int a, b;
        cin >> op >> a >> b;
        if (op == "add") cout << calc.add(a, b) << '\n';
        else if (op == "subtract") cout << calc.subtract(a, b) << '\n';
        else if (op == "multiply") cout << calc.multiply(a, b) << '\n';
        else if (op == "divide") cout << calc.divide(a, b) << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

class Calculator {
    public int add(int a, int b) { return a + b; }
    public int subtract(int a, int b) { return a - b; }
    public long multiply(int a, int b) { return 1L * a * b; }
    public String divide(int a, int b) {
        if (b == 0) return "Division by zero";
        return String.valueOf(a / b);
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int n = Integer.parseInt(br.readLine().trim());
        Calculator calc = new Calculator();
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < n; ++i) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            String op = st.nextToken();
            int a = Integer.parseInt(st.nextToken());
            int b = Integer.parseInt(st.nextToken());
            switch (op) {
                case "add": sb.append(calc.add(a, b)).append('\n'); break;
                case "subtract": sb.append(calc.subtract(a, b)).append('\n'); break;
                case "multiply": sb.append(calc.multiply(a, b)).append('\n'); break;
                case "divide": sb.append(calc.divide(a, b)).append('\n'); break;
            }
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

class Calculator:
    def add(self, a, b):
        return a + b
    def subtract(self, a, b):
        return a - b
    def multiply(self, a, b):
        return a * b
    def divide(self, a, b):
        if b == 0:
            return "Division by zero"
        return a // b  # integer division truncates toward negative infinity, but inputs avoid negative division

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    n = int(data[0])
    calc = Calculator()
    out = []
    for i in range(1, n + 1):
        op, a_str, b_str = data[i].split()
        a, b = int(a_str), int(b_str)
        if op == 'add':
            out.append(str(calc.add(a, b)))
        elif op == 'subtract':
            out.append(str(calc.subtract(a, b)))
        elif op == 'multiply':
            out.append(str(calc.multiply(a, b)))
        elif op == 'divide':
            out.append(str(calc.divide(a, b)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

